// ── Parámetros de entrada ─────────────────────────────────────────
const params = $('Execute Workflow Trigger').first().json;

const query         = (params.query    || '').toLowerCase().trim();
const genre         = (params.genre    || '').toLowerCase().trim();
const language      = (params.language || '').toLowerCase().trim();
const country       = (params.country  || '').toLowerCase().trim();
const minRating     = parseFloat(params.min_rating) || 0;
const maxRating     = (params.max_rating !== undefined && params.max_rating !== '') ? parseFloat(params.max_rating) : 10;
const minPopularity = parseFloat(params.min_popularity) || 0;
const maxPopularity = (params.max_popularity !== undefined && params.max_popularity !== '') ? parseFloat(params.max_popularity) : 999999;
const yearParam     = (params.year || '').trim();
const limitParam    = parseInt(params.limit) || 5;
const sortMode      = (params.sort_mode || '').toLowerCase().trim(); // 'worst', 'best', 'popular', 'random'

// ── Umbral automático de votos ────────────────────────────────────
const minVotesRaw  = parseFloat(params.min_votes) || 0;
const autoMinVotes = minRating > 0 ? 300 : (maxRating < 10 ? 30 : 10);
const minVotes     = Math.max(minVotesRaw, autoMinVotes);

let results = items.map(i => i.json);

// ── Descartar sin datos ───────────────────────────────────────────
results = results.filter(m => parseFloat(m.vote_average) > 0 && parseFloat(m.vote_count) > 0);

// ── Filtros ───────────────────────────────────────────────────────
if (genre) {
  results = results.filter(m => m.genres && m.genres.toLowerCase().includes(genre));
}
if (language) {
  results = results.filter(m => m.language && m.language.toLowerCase() === language);
}
if (country) {
  results = results.filter(m => m.country && m.country.toLowerCase().includes(country));
}
if (minRating > 0) {
  results = results.filter(m => parseFloat(m.vote_average) >= minRating);
}
if (maxRating < 10) {
  results = results.filter(m => parseFloat(m.vote_average) <= maxRating);
}
if (minPopularity > 0) {
  results = results.filter(m => parseFloat(m.popularity) >= minPopularity);
}
if (maxPopularity < 999999) {
  results = results.filter(m => parseFloat(m.popularity) <= maxPopularity);
}

// ── Mínimo de votos ───────────────────────────────────────────────
results = results.filter(m => parseFloat(m.vote_count) >= minVotes);

// ── Año ───────────────────────────────────────────────────────────
if (yearParam) {
  let startYear, endYear;
  if (yearParam.includes('-')) {
    const parts = yearParam.split('-').map(Number);
    startYear = parts[0];
    endYear   = parts[1];
  } else {
    startYear = endYear = Number(yearParam);
  }
  results = results.filter(m => {
    const y = parseInt(m.release_year);
    return !isNaN(y) && y >= startYear && y <= endYear;
  });
}

// ── Búsqueda libre ────────────────────────────────────────────────
if (query) {
  results = results.filter(m =>
    (m.title       && m.title.toLowerCase().includes(query))       ||
    (m.description && m.description.toLowerCase().includes(query)) ||
    (m.cast        && m.cast.toLowerCase().includes(query))        ||
    (m.director    && m.director.toLowerCase().includes(query))
  );
}

// ── Sin resultados ────────────────────────────────────────────────
if (results.length === 0) {
  return [{ json: { noResults: true } }];
}

// ── Ordenar ───────────────────────────────────────────────────────
if (sortMode === 'random') {
  // Aleatorio puro — Fisher-Yates shuffle
  // Filtra mínimo 500 votos para evitar películas oscuras con rating inflado
  const pool = results.filter(m => parseFloat(m.vote_count) >= 500);
  const base = pool.length >= limitParam ? pool : results;
  for (let i = base.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [base[i], base[j]] = [base[j], base[i]];
  }
  results = base;
} else if (sortMode === 'worst' || maxRating < 10) {
  // Peor primero
  results.sort((a, b) => parseFloat(a.vote_average) - parseFloat(b.vote_average));
} else if (sortMode === 'popular' || minPopularity > 0) {
  // Más popular primero
  results.sort((a, b) => parseFloat(b.popularity) - parseFloat(a.popularity));
} else if (sortMode === 'best' || minRating > 0) {
  // Score ponderado estilo IMDB
  const M = 300;
  const C = minRating > 0 ? minRating : 6;
  results.sort((a, b) => {
    const va = parseFloat(a.vote_count) || 0, ra = parseFloat(a.vote_average) || 0;
    const vb = parseFloat(b.vote_count) || 0, rb = parseFloat(b.vote_average) || 0;
    const wsA = (va/(va+M))*ra + (M/(va+M))*C;
    const wsB = (vb/(vb+M))*rb + (M/(vb+M))*C;
    return wsB - wsA;
  });
} else {
  // Default: por rating descendente
  results.sort((a, b) => parseFloat(b.vote_average) - parseFloat(a.vote_average));
}

results = results.slice(0, Math.min(limitParam, 10));

// ── Devolver SOLO campos necesarios y verificados ─────────────────
return results.map(r => ({
  json: {
    title:        (r.title        || '').trim(),
    release_year: (r.release_year || '').trim(),
    genres:       (r.genres       || '').trim(),
    language:     (r.language     || '').trim(),
    country:      (r.country      || '').trim(),
    director:     (r.director     || '').trim(),
    cast:         (r.cast         || '').trim(),
    description:  (r.description  || '').trim(),
    vote_average: parseFloat(r.vote_average || 0).toFixed(1),
    vote_count:   parseInt(r.vote_count    || 0),
    popularity:   parseFloat(r.popularity  || 0).toFixed(1)
  }
}));
